    const actualValues = ctx.searchParams.getAll(name);

    const result =
      expectedValue === null ? actualValues.length === 0 : actualValues.includes(expectedValue);

    ctx.log(result, `query param "${name}"`, expectedValue, actualValues.join(','));

    return result;
  }
}

